    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool is_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    if (!controller->has_valid_turbidity) {
        return !controller->has_valid_level || (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
    }
    if (!controller->has_valid_level) {
        return now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS;
    }
    return (now_ms - controller->last_turbidity_ms > CONTROLLER_SENSOR_TIMEOUT_MS) ||
           (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool level_sufficient(controller_t *controller)
{
    return controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL;
}

static bool turbidity_clear(controller_t *controller)
{
    return controller->has_valid_turbidity && controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU;
}

static bool turbidity_disturbance_settling(controller_t *controller)
{
    return controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU;
}

static bool turbidity_disturbance_draining(controller_t *controller)
{
    return controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle timeout or malformed input - go to safe idle */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.timed_out = true;
        output.changed = true;
        return output;
    }

    /* Check sensor timeout based on current time */
    if (is_sensor_timeout(controller, input.now_ms)) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.timed_out = true;
        output.changed = true;
        return output;
    }

    /* Update sensor freshness based on input type */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Check for COMPLETE state (LEVEL < 15) */
    if (!level_sufficient(controller)) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_COMPLETE;
        output.changed = true;
        return output;
    }

    /* Stay in SAFE_IDLE until both sensors valid */
    if (!controller->has_valid_turbidity || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.changed = true;
        return output;
    }

    /* Clear streak logic - only count valid TURB inputs */
    if (turbidity_clear(controller)) {
        controller->clear_streak_count++;
    } else {
        controller->clear_streak_count = 0;
    }

    /* STATE FILTERING: TURB > 35 and LEVEL >= 40 */
    if (controller->state == CONTROLLER_STATE_SAFE_IDLE) {
        if (!turbidity_clear(controller)) {
            /* Cloudy with sufficient level - start filtering */
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.changed = true;
        } else {
            /* Both sensors valid and clear - stay in SAFE_IDLE */
            controller_set_safe_idle(controller);
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.changed = true;
        }
    }
    /* STATE FILTERING: TURB <= 35 increments clear streak */
    else if (controller->state == CONTROLLER_STATE_FILTERING) {
        if (turbidity_clear(controller)) {
            /* Increment clear streak */
            controller->clear_streak_count++;
            /* Check if we should enter SETTLING */
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                controller->filter_on = false;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_SETTLING;
                controller->settling_started_ms = input.now_ms;
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.changed = true;
            }
        } else {
            /* TURB > 35 - reset clear streak but stay in FILTERING */
            controller->clear_streak_count = 0;
            /* Keep filter on, drain closed */
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.changed = false;
        }
    }
    /* STATE SETTLING: Check settle conditions */
    else if (controller->state == CONTROLLER_STATE_SETTLING) {
        uint32_t time_since_settling = input.now_ms - controller->settling_started_ms;

        /* TURB > 40 during settling - reset and return to FILTERING */
        if (turbidity_disturbance_settling(controller)) {
            controller->clear_streak_count = 0;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.changed = true;
        } else if (time_since_settling >= CONTROLLER_SETTLING_MS) {
            /* Check settle conditions: 400ms elapsed, latest TURB <= 35, LEVEL >= 40 */
            if (turbidity_clear(controller)) {
                controller->filter_on = false;
                controller->drain_open = true;
                controller->state = CONTROLLER_STATE_DRAINING;
                output.filter_on = controller->filter_on;
                output.drain_open = controller->drain_open;
                output.state = controller->state;
                output.changed = true;
            } else {
                /* TURB > 35 but not yet > 40 - stay in SETTLING, keep drain closed */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SETTLING;
                output.changed = false;
            }
        } else {
            /* Not enough time elapsed - stay in SETTLING with drain closed */
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SETTLING;
            output.changed = false;
        }
    }
    /* STATE DRAINING: Check for disturbance */
    else if (controller->state == CONTROLLER_STATE_DRAINING) {
        if (turbidity_disturbance_draining(controller)) {
            /* TURB > 50 and LEVEL >= 40 - close drain, turn filter on, reset streak, return to FILTERING */
            controller->drain_open = false;
            controller->filter_on = true;
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            output.filter_on = controller->filter_on;
            output.drain_open = controller->drain_open;
            output.state = controller->state;
            output.changed = true;
        } else {
            /* No disturbance - keep draining */
            output.filter_on = false;
            output.drain_open = true;
            output.state = CONTROLLER_STATE_DRAINING;
            output.changed = false;
        }
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

